import { createContextId } from "@builder.io/qwik";

/**
 * Theme values supported by the application.
 */
export const THEMES = ["light", "dark"] as const;
export type Theme = (typeof THEMES)[number];

/**
 * Locales supported by the application.
 */
export const LOCALES = ["en", "es"] as const;
export type Locale = (typeof LOCALES)[number];

export const DEFAULT_THEME: Theme = "light";
export const DEFAULT_LOCALE: Locale = "en";

export const THEME_COOKIE = "theme";
export const LOCALE_COOKIE = "locale";

export function isTheme(value: unknown): value is Theme {
  return typeof value === "string" && (THEMES as readonly string[]).includes(value);
}

export function isLocale(value: unknown): value is Locale {
  return typeof value === "string" && (LOCALES as readonly string[]).includes(value);
}

export function resolveTheme(raw: string | undefined | null): Theme {
  return isTheme(raw) ? raw : DEFAULT_THEME;
}

export function resolveLocale(raw: string | undefined | null): Locale {
  return isLocale(raw) ? raw : DEFAULT_LOCALE;
}

/**
 * Parse a raw `Cookie` request header into a plain map. Used in places
 * (like the SSR entry) where the full Qwik City request event is not
 * available.
 */
export function parseCookieHeader(header: string | null | undefined): Record<string, string> {
  const out: Record<string, string> = {};
  if (!header) return out;
  for (const segment of header.split(";")) {
    const trimmed = segment.trim();
    if (!trimmed) continue;
    const eq = trimmed.indexOf("=");
    if (eq <= 0) continue;
    const name = trimmed.slice(0, eq).trim();
    const value = trimmed.slice(eq + 1).trim();
    if (!name) continue;
    try {
      out[name] = decodeURIComponent(value);
    } catch {
      out[name] = value;
    }
  }
  return out;
}

/**
 * Shape of the values published through Qwik's Context API. Components
 * inside the root layout can read this with `useContext(PreferencesContext)`.
 */
export interface Preferences {
  theme: Theme;
  locale: Locale;
}

/**
 * Shared keys used by the route middleware, routeLoader$, and the SSR
 * entry to stash and retrieve the per-request preferences.
 */
export const SHARED_THEME_KEY = "preferences.theme";
export const SHARED_LOCALE_KEY = "preferences.locale";

/**
 * The Qwik Context ID for the per-request preferences. The root layout
 * provides it via `useContextProvider`; descendants consume it with
 * `useContext`.
 */
export const PreferencesContext = createContextId<Preferences>(
  "app.preferences",
);

import type { Locale } from "./preferences";

/**
 * In-repo translation dictionary. Keys used by the home page must always be
 * present for every supported locale.
 */
export interface Dictionary {
  title: string;
  greeting: string;
}

export const DICTIONARY: Record<Locale, Dictionary> = {
  en: {
    title: "Preferences",
    greeting: "Hello",
  },
  es: {
    title: "Preferencias",
    greeting: "Hola",
  },
};

export function translate(locale: Locale): Dictionary {
  return DICTIONARY[locale];
}

import { component$, useContext } from "@builder.io/qwik";
import { Form, routeAction$, type DocumentHead } from "@builder.io/qwik-city";
import { translate } from "../dictionary";
import {
  isLocale,
  isTheme,
  PreferencesContext,
  THEME_COOKIE,
  LOCALE_COOKIE,
} from "../preferences";

/**
 * Persist the user's chosen theme + locale into cookies so that subsequent
 * requests reflect the new preferences on the very first server response.
 * The form must submit two fields named exactly `theme` and `locale`.
 */
export const useSavePreferences = routeAction$((form, ev) => {
  const theme = isTheme(form.theme) ? form.theme : "light";
  const locale = isLocale(form.locale) ? form.locale : "en";

  ev.cookie.set(THEME_COOKIE, theme, { path: "/" });
  ev.cookie.set(LOCALE_COOKIE, locale, { path: "/" });

  return { theme, locale };
});

export default component$(() => {
  // Pull the SSR-resolved preferences out of the Context that the root
  // layout populated.
  const prefs = useContext(PreferencesContext);
  const dict = translate(prefs.locale);

  // Resolve the action store once per render so we can pass it to <Form>.
  const action = useSavePreferences();

  return (
    <>
      <h1>{dict.title}</h1>
      <p>{dict.greeting}</p>

      <Form action={action}>
        <label>
          Theme:
          <select name="theme" value={prefs.theme}>
            <option value="light">light</option>
            <option value="dark">dark</option>
          </select>
        </label>
        <label>
          Locale:
          <select name="locale" value={prefs.locale}>
            <option value="en">en</option>
            <option value="es">es</option>
          </select>
        </label>
        <button type="submit">Save</button>
      </Form>
    </>
  );
});

export const head: DocumentHead = {
  title: "Preferences",
};

/**
 * WHAT IS THIS FILE?
 *
 * SSR entry point, in all cases the application is rendered outside the browser, this
 * entry point will be the common one.
 *
 * - Server (express, cloudflare...)
 * - npm run start
 * - npm run preview
 * - npm run build
 *
 */
import {
  renderToStream,
  type RenderToStreamOptions,
} from "@builder.io/qwik/server";
import Root from "./root";
import {
  parseCookieHeader,
  resolveLocale,
  resolveTheme,
} from "./preferences";

export default function (opts: RenderToStreamOptions) {
  // The Qwik City request handler has already populated
  // `serverData.requestHeaders` (with the Cookie header) and
  // `serverData.locale` (set via `event.locale(...)` from the route
  // middleware). We re-derive the resolved theme + locale here so the very
  // first bytes of the response carry the correct `data-theme` and `lang`
  // attributes on the <html> element -- no client-side JS required.
  const cookieHeader = opts.serverData?.requestHeaders?.cookie as
    | string
    | undefined;
  const cookies = parseCookieHeader(cookieHeader ?? null);

  const theme = resolveTheme(cookies.theme ?? null);
  // Prefer the locale that the middleware resolved through `ev.locale()`,
  // fall back to parsing the cookie ourselves.
  const serverLocale =
    typeof opts.serverData?.locale === "string"
      ? opts.serverData.locale
      : undefined;
  const locale = resolveLocale(
    serverLocale && serverLocale !== "*"
      ? serverLocale
      : cookies.locale ?? null,
  );

  return renderToStream(<Root />, {
    ...opts,
    // Use container attributes to set attributes on the html tag.
    // `opts.containerAttributes` is populated by Qwik City with `q:route`,
    // so we must preserve it for routing to keep working. We put our own
    // attributes *after* the spread so they always win.
    containerAttributes: {
      ...opts.containerAttributes,
      lang: locale,
      "data-theme": theme,
    },
    serverData: {
      ...opts.serverData,
      theme,
      locale,
    },
  });
}

import { component$, isDev } from "@builder.io/qwik";
import { QwikCityProvider, RouterOutlet } from "@builder.io/qwik-city";
import { RouterHead } from "./components/router-head/router-head";

import "./global.css";

export default component$(() => {
  /**
   * The root of a QwikCity site always start with the <QwikCityProvider> component,
   * immediately followed by the document's <head> and <body>.
   *
   * Don't remove the `<head>` and `<body>` elements.
   */

  return (
    <QwikCityProvider>
      <head>
        <meta charset="utf-8" />
        {!isDev && (
          <link
            rel="manifest"
            href={`${import.meta.env.BASE_URL}manifest.json`}
          />
        )}
        <RouterHead />
      </head>
      <body>
        <RouterOutlet />
      </body>
    </QwikCityProvider>
  );
});
